const today = new Date();

today.setDate(today.getDate() - $input.first().json.days_ago);

const yyyy = today.getFullYear();
const mm = String(today.getMonth() + 1).padStart(2, '0');
const dd = String(today.getDate()).padStart(2, '0');

const after = `${yyyy}/${mm}/${dd}`;

const next = new Date(today);
next.setDate(next.getDate() + 1);

const afterNext = `${next.getFullYear()}/${String(next.getMonth()+1).padStart(2,'0')}/${String(next.getDate()).padStart(2,'0')}`;

return {
  after,
  before: afterNext
};

const messages = $node["Step 8: Get email information about thread_id"].json.messages || [];
const getHeader = (headers, name) =>
  headers.find(h => h.name === name)?.value || null;

function parseRecipients(value) {
  if (!value) return [];

  return value
    .split(',')
    .map(r => {
      const trimmed = r.trim();
      const match = trimmed.match(/^(.*?)\s*<([^>]+)>$/);

      if (match) {
        return {
          name: match[1].replace(/"/g, '').trim(),
          email: match[2].toLowerCase().trim()
        };
      }

      return {
        name: trimmed.split('@')[0],
        email: trimmed.toLowerCase()
      };
    })
    .filter(r => r.email);
}

const unique = (arr) =>
  [...new Map(arr.map(r => [r.email, r])).values()];

let originalRecipients = [];

for (const msg of messages) {
  const headers = msg.payload?.headers || [];

  const inReply = getHeader(headers, "In-Reply-To");

  // The first message does NOT have an In-Reply-To
  if (!inReply) {
    const toList = parseRecipients(getHeader(headers, "To"));
    originalRecipients.push(...toList);
  }
}

originalRecipients = unique(originalRecipients);

let replied = [];
let bounced = [];
let autoReply = [];

for (const msg of messages) {
  const headers = msg.payload?.headers || [];

  const from = parseRecipients(getHeader(headers, "From"))[0];
  if (!from) continue;

  const subject = (getHeader(headers, "Subject") || "").toLowerCase();
  const inReply = getHeader(headers, "In-Reply-To");
  const autoSub = getHeader(headers, "Auto-Submitted");

  const fromEmail = from.email;

  /******** BOUNCE ********/
  const isBounce =
    fromEmail.includes("mailer-daemon") ||
    subject.includes("delivery status notification") ||
    subject.includes("failure notice");

  if (isBounce) {
    bounced.push(...originalRecipients);
    continue;
  }

  /******** AUTO ********/
  if (autoSub) {
    autoReply.push(from);
    continue;
  }

  /******** REAL REPLY ********/
  if (inReply) {
    replied.push(from);
  }
}

replied = unique(replied);
bounced = unique(bounced);
autoReply = unique(autoReply);

const repliedSet = new Set(replied.map(r => r.email));
const bouncedSet = new Set(bounced.map(r => r.email));

const deliver = originalRecipients.filter(
  r => !bouncedSet.has(r.email)
);

const noResponse = deliver.filter(
  r => !repliedSet.has(r.email)
);

return {
  deliverableEmails: deliver,
  repliedEmails: replied,
  bounceEmails: bounced,
  autoReplies: autoReply,
  noResponse
};

const items = $input.all().map(i => i.json);

let deliver = [];
let replied = [];
let bounce = [];
let autoReply = [];
let noResponse = [];

for (const data of items) {
  deliver.push(...(data.deliverableEmails || []));
  replied.push(...(data.repliedEmails || []));
  bounce.push(...(data.bounceEmails || []));
  autoReply.push(...(data.autoReplies || []));
  noResponse.push(...(data.noResponse || []));
}

const unique = (arr) =>
  [...new Map(arr.map(x => [x.email, x])).values()];

deliver = unique(deliver);
replied = unique(replied);
bounce = unique(bounce);
autoReply = unique(autoReply);
noResponse = unique(noResponse);

return [
  {
    json: {
      deliverableEmails: deliver,
      repliedEmails: replied,
      bounceEmails: bounce,
      autoReplies: autoReply,
      noResponse: noResponse
    }
  }
];

const inputData = $input.all();
const list_ids = inputData[0]?.json?.result?.records[0]?.list_ids || [];
const id = inputData[0]?.json?.result?.records[0]?.id;
let islist_ids = false;

if (list_ids.length > 0) {
    islist_ids = list_ids.some(item => item.id === $node['Step 2: Set Variables'].json.020_Good_to_send);
}

return { islist_ids, id };

